    14→/// Global random number generator state for game logic
    15→static GAME_LOGIC_SEED: Mutex<[u32; 6]> = Mutex::new([
    16→    0xf22d0e56, 0x883126e9, 0xc624dd2f, 0x702c49c, 0x9e353f7d, 0x6fdf3b64
    17→]);
