    19→/// Adds two numbers with carry flag (matching C++ ADC macro)
    20→fn adc(a: u32, b: u32, carry: u32) -> (u32, u32) {
    21→    let sum = a.wrapping_add(b).wrapping_add(carry);
    22→    let new_carry = if sum < a || sum < b { 1 } else { 0 };
    23→    (sum, new_carry)
    24→}
