    26→/// Generate random value using game logic seed (matching C++ randomValue function)
    27→fn random_value(seed: &mut [u32; 6]) -> u32 {
    28→    let mut ax;
    29→    let mut c = 0;
    30→    
    31→    // Add with carry operations
    32→    (ax, c) = adc(seed[5], seed[4], c);
    33→    seed[4] = ax;
    34→    
    35→    (ax, c) = adc(ax, seed[3], c);
    36→    seed[3] = ax;
    37→    
    38→    (ax, c) = adc(ax, seed[2], c);
    39→    seed[2] = ax;
    40→    
    41→    (ax, c) = adc(ax, seed[1], c);
    42→    seed[1] = ax;
    43→    
    44→    (ax, c) = adc(ax, seed[0], c);
    45→    seed[0] = ax;
    46→    
    47→    // Increment seed array, bubbling up the carries
    48→    seed[5] = seed[5].wrapping_add(1);
    49→    if seed[5] == 0 {
    50→        seed[4] = seed[4].wrapping_add(1);
    51→        if seed[4] == 0 {
    52→            seed[3] = seed[3].wrapping_add(1);
    53→            if seed[3] == 0 {
    54→                seed[2] = seed[2].wrapping_add(1);
    55→                if seed[2] == 0 {
    56→                    seed[1] = seed[1].wrapping_add(1);
    57→                    if seed[1] == 0 {
    58→                        seed[0] = seed[0].wrapping_add(1);
    59→                        ax = ax.wrapping_add(1);
    60→                    }
    61→                }
    62→            }
    63→        }
    64→    }
    65→    
    66→    ax
    67→}
