    69→/// Gets game logic random integer value (matching C++ GetGameLogicRandomValue)
    70→pub fn get_game_logic_random_value(lo: Int, hi: Int) -> Int {
    71→    if hi < lo {
    72→        return hi;
    73→    }
    74→    
    75→    let delta = (hi - lo + 1) as u32;
    76→    if delta == 0 {
    77→        return hi;
    78→    }
    79→    
    80→    let mut seed = GAME_LOGIC_SEED.lock().unwrap();
    81→    let rval = (random_value(&mut *seed) % delta) as Int + lo;
    82→    rval
    83→}
    84→
    85→/// Gets game logic random real value (matching C++ GetGameLogicRandomValueReal)
    86→pub fn get_game_logic_random_value_real(lo: Real, hi: Real) -> Real {
    87→    if hi <= lo {
    88→        return hi;
    89→    }
    90→    
    91→    let delta = hi - lo;
    92→    let mult_factor = 1.0 / (2.0_f32.powi(32) - 1.0);
    93→    
    94→    let mut seed = GAME_LOGIC_SEED.lock().unwrap();
    95→    let rval = (random_value(&mut *seed) as Real * mult_factor) * delta + lo;
    96→    rval
    97→}
