    99→/// Gets the CRC of the game logic random seed state (matching C++ GetGameLogicRandomSeedCRC)
   100→/// CRITICAL for network synchronization - ensures all players have same random state
   101→pub fn get_game_logic_random_seed_crc() -> UnsignedInt {
   102→    let seed = GAME_LOGIC_SEED.lock().unwrap();
   103→    // Calculate CRC32 of the entire seed array - 6 * 4 = 24 bytes
   104→    let seed_bytes: &[u8] = unsafe {
   105→        std::slice::from_raw_parts(seed.as_ptr() as *const u8, 6 * 4)
   106→    };
   107→    crc32fast::hash(seed_bytes)
   108→}
   109→
   110→/// Sets the game logic random seed (matching C++ SetGameLogicRandomSeed)
   111→pub fn set_game_logic_random_seed(new_seed: [u32; 6]) {
   112→    let mut seed = GAME_LOGIC_SEED.lock().unwrap();
   113→    *seed = new_seed;
   114→}
